<?php
session_start();
require_once '../config/config.php';
if(!isAdmin()) { header('Location: login.php'); exit; }
if(isset($_POST['update_order'])) {
    $stmt = $pdo->prepare("UPDATE orders SET order_status=?, payment_status=? WHERE id=?");
    $stmt->execute([$_POST['order_status'], $_POST['payment_status'], $_POST['order_id']]);
    header('Location: orders.php?msg=updated');
    exit;
}
if(isset($_POST['clear_payment'])) {
    $stmt = $pdo->prepare("UPDATE orders SET payment_status='completed', order_status='processing' WHERE id=?");
    $stmt->execute([$_POST['order_id']]);
    header('Location: orders.php?msg=cleared');
    exit;
}
$orders = $pdo->query("SELECT * FROM orders ORDER BY created_at DESC")->fetchAll();
$pendingCount = $pdo->query("SELECT COUNT(*) FROM orders WHERE payment_status='pending'")->fetchColumn();
$processingCount = $pdo->query("SELECT COUNT(*) FROM orders WHERE order_status='processing'")->fetchColumn();
$deliveredCount = $pdo->query("SELECT COUNT(*) FROM orders WHERE order_status='delivered'")->fetchColumn();
?>
<!DOCTYPE html>
<html><head><title>Order Management - African Fashion</title><link href="https://cdn.jsdelivr.net/npm/bootstrap@5.1.3/dist/css/bootstrap.min.css" rel="stylesheet"><link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0/css/all.min.css"><style>.sidebar{min-height:100vh;background:#1a1a2e;}.sidebar .nav-link{color:white;padding:12px20px;}.sidebar .nav-link:hover{background:#f36f25;}</style></head>
<body><div class="container-fluid"><div class="row"><div class="col-md-2 p-0 sidebar"><div class="text-center py-3"><h5 class="text-white"><i class="fas fa-tshirt"></i> Admin Panel</h5></div><nav class="nav flex-column"><a class="nav-link" href="index.php">Dashboard</a><a class="nav-link" href="products.php">Products</a><a class="nav-link active" href="orders.php">Orders</a><a class="nav-link" href="inventory.php">Inventory</a><a class="nav-link" href="logout.php">Logout</a></nav></div><div class="col-md-10 p-4"><h2>Order Management</h2><div class="row mb-4"><div class="col-md-4"><div class="card text-white bg-warning"><div class="card-body"><h3><?php echo $pendingCount; ?></h3><p>Pending Orders</p></div></div></div><div class="col-md-4"><div class="card text-white bg-info"><div class="card-body"><h3><?php echo $processingCount; ?></h3><p>Processing</p></div></div></div><div class="col-md-4"><div class="card text-white bg-success"><div class="card-body"><h3><?php echo $deliveredCount; ?></h3><p>Delivered</p></div></div></div></div><?php if(isset($_GET['msg'])): ?><div class="alert alert-success">Order updated successfully!</div><?php endif; ?><div class="table-responsive"><table class="table table-bordered"><thead class="table-dark"><tr><th>Order #</th><th>Customer</th><th>Amount</th><th>Payment</th><th>Status</th><th>Date</th><th>Actions</th></tr></thead><tbody><?php foreach($orders as $o): ?><tr><td><strong><?php echo $o['order_number']; ?></strong></td><td><?php echo htmlspecialchars($o['customer_name']); ?><br><small><?php echo $o['customer_email']; ?></small><br><small><?php echo $o['customer_phone']; ?></small></td><td><?php echo $o['total_amount']; ?> <?php echo $o['currency_code']; ?></td><td><span class="badge bg-<?php echo $o['payment_status']=='completed'?'success':'warning'; ?>"><?php echo $o['payment_status']; ?></span></td><td><span class="badge bg-<?php echo $o['order_status']=='delivered'?'success':($o['order_status']=='cancelled'?'danger':'secondary'); ?>"><?php echo $o['order_status']; ?></span></td><td><?php echo date('M d, Y', strtotime($o['created_at'])); ?></td><td><button class="btn btn-sm btn-primary" data-bs-toggle="modal" data-bs-target="#modal<?php echo $o['id']; ?>"><i class="fas fa-edit"></i> Update</button><?php if($o['payment_status']=='pending'): ?><form method="POST" style="display:inline-block" onsubmit="return confirm('Clear payment for this order?')"><input type="hidden" name="order_id" value="<?php echo $o['id']; ?>"><button type="submit" name="clear_payment" class="btn btn-sm btn-success"><i class="fas fa-check"></i> Clear Payment</button></form><?php endif; ?><div class="modal fade" id="modal<?php echo $o['id']; ?>" tabindex="-1"><div class="modal-dialog"><div class="modal-content"><div class="modal-header"><h5>Update Order <?php echo $o['order_number']; ?></h5><button type="button" class="btn-close" data-bs-dismiss="modal"></button></div><form method="POST"><div class="modal-body"><input type="hidden" name="order_id" value="<?php echo $o['id']; ?>"><div class="mb-3"><label>Order Status</label><select name="order_status" class="form-control"><option <?php echo $o['order_status']=='pending'?'selected':''; ?>>pending</option><option <?php echo $o['order_status']=='processing'?'selected':''; ?>>processing</option><option <?php echo $o['order_status']=='shipped'?'selected':''; ?>>shipped</option><option <?php echo $o['order_status']=='delivered'?'selected':''; ?>>delivered</option><option <?php echo $o['order_status']=='cancelled'?'selected':''; ?>>cancelled</option></select></div><div class="mb-3"><label>Payment Status</label><select name="payment_status" class="form-control"><option <?php echo $o['payment_status']=='pending'?'selected':''; ?>>pending</option><option <?php echo $o['payment_status']=='completed'?'selected':''; ?>>completed</option><option <?php echo $o['payment_status']=='failed'?'selected':''; ?>>failed</option></select></div></div><div class="modal-footer"><button type="submit" name="update_order" class="btn btn-primary">Save Changes</button></div></form></div></div></div></td></tr><?php endforeach; ?></tbody></table></div></div></div></div></body>
</html>